functions.function_body:
{
    bool found = true;
    uint8_t type  = GET_DESC_TYPE(type_index);

    switch (type) {
        case USB_DESC_TYPE_DEVICE:
        {
            *data = (uint8_t *)msc_device_descriptor;
            *len  = sizeof(msc_device_descriptor);
        } break;

        case USB_DESC_TYPE_CONFIGURATION:
        {
            *data = (uint8_t *)msc_config_descriptor;
            *len  = sizeof(msc_config_descriptor);
        } break;

        case USB_DESC_TYPE_STRING:
        {
            uint8_t index = GET_DESC_INDEX(type_index);
            if (index == USB_STRING_LANGID_INDEX) {
                *data = (uint8_t *)msc_langid_string;
                *len  = sizeof(msc_langid_string);
            } else if (index == USB_STRING_MANUFACT_INDEX) {
                *data = (uint8_t *)msc_manufact_string;
                *len  = sizeof(msc_manufact_string);
            } else if (index == USB_STRING_PRODUCT_INDEX){
                *data = (uint8_t *)msc_product_string;
                *len  = sizeof(msc_product_string);
            } else {
                found = false;
            }
        } break;

        default:
        {
            found = false;
        } break;
    }

    return found;
}

